trackedTool("cdp_store_state", 'Read app store state (Redux, Zustand, Jotai, React Query). Use path to query specific slice (e.g. "cart.items", "auth.user.name"). Use storeType to target a specific store when multiple exist. Redux auto-detected via fiber Provider. Zustand requires: if (__DEV__) global.__ZUSTAND_STORES__ = { store }. Jotai requires: if (__DEV__) { global.__JOTAI_STORE__ = store; global.__JOTAI_ATOMS__ = { name: atom } }', {
  path: external_exports.string().optional().describe('Dot-path into store state (e.g. "cart.items")'),
  storeType: external_exports.enum(["redux", "zustand", "jotai", "react-query"]).optional().describe("Target a specific store type. Useful when app has both Redux and React Query.")
}, createStoreStateHandler(getClient));
trackedTool("cdp_navigate", "Navigate to any screen by name, including nested stack screens that __NAV_REF__.navigate() cannot reach. Builds a nested dispatch action by walking the navigation state tree. Works across tabs, stacks, and modals.", {
  screen: external_exports.string().describe('Screen name to navigate to (e.g. "AllTasks", "Dashboard", "ProfileEditModal")'),
  params: external_exports.record(external_exports.unknown()).optional().describe('Screen params (e.g. { id: "1" })')
}, withConnection(getClient, async (args, client2) => {
  const paramsArg = args.params ? JSON.stringify(args.params) : "undefined";
  const expression = `__RN_AGENT.navigateTo(${JSON.stringify(args.screen)}, ${paramsArg})`;
  const result = await client2.evaluate(expression);
  if (result.error)
    return failResult(`Navigate error: ${result.error}`);
  if (typeof result.value !== "string")
    return failResult("Unexpected response");
  let parsed;
  try {
    parsed = JSON.parse(result.value);
  } catch {
    return okResult({ raw: result.value });
  }
  if (parsed !== null && typeof parsed === "object" && "__agent_error" in parsed) {
    return failResult(String(parsed.__agent_error));
  }
  const cfg = loadVerificationConfig(getCachedProjectRoot());
  return annotateMutationAbsence(okResult(parsed), {
    client: client2,
    screenName: args.screen,
    source: "cdp_navigate",
    successShapes: cfg.successShapes,
    mutationMethods: cfg.mutationMethods
  });
}));
