  durationMs: external_exports.number().int().min(50).max(1e4).optional().describe("Swipe duration in ms (slower = more precise, default ~300). Note: the non-exact path may normalize/clamp very short durations \u2014 use exact: true for an unclamped duration."),
  count: external_exports.number().int().min(1).max(50).optional().describe("Repeat swipe N times (incompatible with exact: true)"),
